def set_master_key(raw_key):
    """Set the master key (stores its sha256 hex digest)."""
    global masterKey
    if raw_key is None:
        masterKey = None
    else:
        if isinstance(raw_key, str):
            raw_key = raw_key.encode()
        masterKey = sha256(raw_key).hexdigest()

def _verify_master_key(raw_key):
    """Return True if provided raw_key matches the stored masterKey."""
    global masterKey
    if masterKey is None:
        return False
    if isinstance(raw_key, str):
        raw_key = raw_key.encode()
    return sha256(raw_key).hexdigest() == masterKey

def add_bounty(title, reward, description="", key=None):
    """Add a new bounty. Requires correct master key."""
    if not _verify_master_key(key):
        raise PermissionError("Invalid master key")
    bid = sha256((title + str(time.time())).encode()).hexdigest()[:16]
    entry = {
        "id": bid,
        "title": title,
        "reward": reward,
        "description": description,
        "created_at": time.time(),
    }
    bountyLock.acquire()
    try:
        bountyList.append(entry)
        _save_bounties()
    finally:
        bountyLock.release()
    return bid

def remove_bounty(bounty_id, key=None):
    """Remove a bounty by id. Returns True if removed, False if not found."""
    if not _verify_master_key(key):
        raise PermissionError("Invalid master key")
    removed = False
    bountyLock.acquire()
    try:
        for i, b in enumerate(bountyList):
            if b.get("id") == bounty_id:
                bountyList.pop(i)
                removed = True
                break
        if removed:
            _save_bounties()
    finally:
        bountyLock.release()
    return removed

def get_bounties():
    """Return a deep copy of current bounties (thread-safe)."""
    bountyLock.acquire()
    try:
        return copy.deepcopy(bountyList)
    finally:
        bountyLock.release()

def get_bounty(bounty_id):
    """Return a copy of a single bounty by id or None if not found."""
    bountyLock.acquire()
    try:
        for b in bountyList:
            if b.get("id") == bounty_id:
                return copy.deepcopy(b)
    finally:
        bountyLock.release()
    return None

