class QuandlSpider(scrapy.Spider):
    name = "quandl_spider"
    allowed_domains = ["quandl.com"]

    def start_requests(self):
        """
        Entry point for the spider. Iterate through Quandlset records in the DB,
        fetch the series from Quandl, compute indicators (if available) and yield
        items (as simple dicts to avoid depending on the exact MykgbItem schema).
        """
        qs = Quandlset.objects.filter(active=True)
        for q in qs:
            dataset_code = getattr(q, 'code', None) or getattr(q, 'dataset', None)
            if not dataset_code:
                self.logger.warning("Quandlset record %s has no dataset code, skipping.", q.pk)
                continue

            try:
                # request pandas DataFrame from Quandl
                df = quandl.get(dataset_code,
                                start_date=getattr(q, 'start_date', None),
                                end_date=getattr(q, 'end_date', None),
                                returns="pandas")
            except Exception as exc:
                self.logger.error("Failed to fetch %s from Quandl: %s", dataset_code, exc)
                continue

            # compute indicators if the indicator module exposes a processing function
            indicator_result = None
            try:
                indicator_result = self._compute_indicator(df)
            except Exception:
                self.logger.exception("Indicator computation failed for %s", dataset_code)
                indicator_result = None

            # prepare serializable payload
            try:
                data_json = df.to_json(orient="split")
            except Exception:
                data_json = df.to_dict()

            item = {
                'dataset': dataset_code,
                'data': data_json,
                'indicator': indicator_result,
                'quandlset_id': q.pk,
            }

            yield item

    def _compute_indicator(self, df):
        """
        Try a few common function names on the imported indicator module to compute
        indicator(s) from a pandas DataFrame. Return None if no suitable callable is found.
        """
        candidates = ('process', 'compute', 'run', 'calc', 'calculate', 'indicators', 'indicator')
        for name in candidates:
            func = getattr(indicator, name, None)
            if callable(func):
                # most indicator functions accept a DataFrame and return a serializable result
                return func(df)
        # fallback: if indicator exposes a single callable attribute (besides dunders), use it
        for name in dir(indicator):
            if name.startswith('_'):
                continue
            func = getattr(indicator, name)
            if callable(func):
                return func(df)
        return None

