@classmethod
def load(cls, username):
    """Load a user from Redis. Returns User instance or None if not found."""
    key = f"user:{username}"
    if not redis_db.exists(key):
        return None
    raw = redis_db.hgetall(key)
    # Decode bytes to str if necessary
    data = {}
    for k, v in raw.items():
        if isinstance(k, bytes):
            k = k.decode('utf-8')
        if isinstance(v, bytes):
            v = v.decode('utf-8')
        data[k] = v
    user = cls()
    user.username = data.get("username", username)
    user.password_hash = data.get("password_hash", "")
    user.email = data.get("email", "")
    user.api_key = data.get("api_key", "")
    return user

