def extract_video_id(url):
    """
    Extract a YouTube video id from a variety of YouTube URL formats.
    Returns None if no id can be found.
    """
    if not url:
        return None

    parsed = urlparse(url)
    # Standard watch?v=VIDEOID
    qs = parse_qs(parsed.query)
    if 'v' in qs:
        return qs['v'][0]

    # Short youtu.be/VIDEOID
    if parsed.netloc.endswith('youtu.be'):
        path = parsed.path.lstrip('/')
        if path:
            return path.split('/')[0]

    # /embed/VIDEOID or /v/VIDEOID
    parts = parsed.path.split('/')
    for i, part in enumerate(parts):
        if part in ('embed', 'v') and i + 1 < len(parts):
            return parts[i + 1]

    return None


def _normalize_text(text):
    """Normalize unicode text to NFC and strip surrounding whitespace."""
    if text is None:
        return None
    try:
        # Ensure text is unicode in Python 2
        if not isinstance(text, unicode):
            text = unicode(text, 'utf-8', 'ignore')
    except NameError:
        # Python 3: unicode is not defined
        if not isinstance(text, str):
            text = str(text)
    text = unicodedata.normalize('NFKC', text).strip()
    return text


def _api_get(resource, params, api_key):
    """Helper to call YouTube Data API v3 endpoints."""
    if api_key:
        params = dict(params)
        params['key'] = api_key
    url = yt_api_endpoint.rstrip('/') + '/' + resource
    logger.debug('YouTube API GET %s params=%s', url, params)
    resp = requests.get(url, params=params, timeout=10)
    resp.raise_for_status()
    return resp.json()


def _pafy_video_length_ms(video_id):
    """Return video length in milliseconds using pafy; return None on failure."""
    try:
        p = pafy.new(video_id)
        if hasattr(p, 'length') and p.length:
            return int(p.length * 1000)
    except Exception as e:
        logger.debug('Failed to get duration for %s via pafy: %s', video_id, e)
    return None


def search_youtube(query, api_key=None, max_results=20):
    """
    Search YouTube for videos matching query and return a Mopidy SearchResult.
    Uses the YouTube Data API if api_key is provided; otherwise falls back
    to the API-less search (may be limited/unreliable).
    """
    params = {
        'part': 'snippet',
        'q': query,
        'type': 'video',
        'maxResults': max_results,
    }

    try:
        data = _api_get('search', params, api_key)
    except Exception as e:
        logger.error('YouTube search failed for "%s": %s', query, e)
        return SearchResult(tracks=[], albums=[], artists=[])

    tracks = []
    for item in data.get('items', []):
        vid = None
        # item.id may be a dict like {'kind': 'youtube#video', 'videoId': '...'}
        item_id = item.get('id')
        if isinstance(item_id, dict):
            vid = item_id.get('videoId')
        else:
            # fallback if id is a string or other format
            vid = extract_video_id(item_id)

        if not vid:
            continue

        snippet = item.get('snippet', {})
        title = _normalize_text(snippet.get('title') or '')
        channel = _normalize_text(snippet.get('channelTitle') or '')
        uri = 'youtube:video:%s' % vid

        length_ms = _pafy_video_length_ms(vid)

        artist = Artist(name=channel) if channel else None

        track = Track(
            name=title,
            uri=uri,
            length=length_ms,
            artists=[artist] if artist else [],
            album=None
        )
        tracks.append(track)

    return SearchResult(tracks=tracks, albums=[], artists=[])

